powerpagecomponent.content:
{
  "source": "<!-- REGISTER PAGE (all-in-one: HTML + inline CSS + inline JS) -->

<div class="login-page py-1">
  <div class="container">
    <div class="row justify-content-between">
      <!-- Left column -->
      <div class="col-12 col-md-12 col-lg-6">
        <div class="d-flex flex-column align-items-start h-100">
          <div class="p-4">
            /logo-dark.png
          </div>

          <div class="d-flex justify-content-center login-form w-100">
            <div class="col-12 col-lg-8">
              <h1 class="fs-4 mb-3">Create Account</h1>

              <!-- Local registration (Power Pages built-in) -->
              /Account/Register/
                Create account with email
              </a>

              <!-- Divider -->
              <div class="signin-divider d-flex justify-content-center">
                <p class="mb-0 p-3 bg-white text-gray">Register Using</p>
              </div>

              <!-- External providers -->
              <button class="btn btn-outline-primary w-100 mb-3" onclick="triggerBeazleySignUp()">
                Beazley Account
              </button>

              <button class="btn btn-outline-secondary w-100 mb-3" onclick="triggerGoogleSignUp()">
                <div class="d-flex gap-3 justify-content-center align-items-center">
                  /google.png
                  <span class="fw-bold">Google</span>
                </div>
              </button>

              <button class="btn btn-outline-secondary w-100" onclick="triggerMicrosoftSignUp()">
                <div class="d-flex gap-3 justify-content-center align-items-center">
                  /microsoft.png
                  <span class="fw-bold">Microsoft</span>
                </div>
              </button>
            </div>
          </div>
        </div>
      </div>

      <!-- Right column (hero) -->
      <div class="col-12 col-md-12 col-lg-5">
        <div class="img-wrapper rounded">
          <div class="login-slide-sec h-100 p-4 py-5">
            <div class="right-content rounded d-flex align-items-center flex-wrap">
              <h1 class="fs-2 text-primary-dark mb-0 fw-bold">
                Manage all your<br/>
                requests with ease!
              </h1>
              <img src="/cards.png"  </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</div>

<!-- Inline CSS (kept minimal and scoped) -->
<style>
  .login-page { min-height: 60vh; }
  .login-form .col-12.col-lg-8 { max-width: 520px; }

  /* Divider line behind the label */
  .signin-divider { position: relative; text-align: center; margin: 24px 0 16px; }
  .signin-divider p { position: relative; z-index: 2; }
  .signin-divider::before {
    content: "";
    position: absolute; top: 50%; left: 0; right: 0;
    height: 1px; background: #e6e6e6;
  }

  /* Right panel background */
  .img-wrapper { background: #f7f9fc; border: 1px solid #eef2f7; padding: 0; }
  .right-content h1 { line-height: 1.2; }

  /* Button tweaks to match look & feel */
  .btn-outline-secondary { border-color: #cfcfcf; }
  .btn-outline-secondary:hover { background: #f0f0f0; }
</style>

<!-- Inline JS (provider triggers) -->
<script>
  (function () {
    // Use redirects; they work even if hidden buttons don't exist on this page.
    function go(path) { window.location.href = path; }

    // External identity providers: adjust paths if your site uses custom routes.
    window.triggerGoogleSignUp = function () {
      // If your sign-in page accepts a provider parameter:
      go('/signin?provider=Google');
      // Alternatively, if you rely on hidden buttons on this page, uncomment:
      // var el = document.getElementById('Google'); if (el) el.click();
    };

    window.triggerMicrosoftSignUp = function () {
      go('/signin?provider=Microsoft');
      // Or: var el = document.getElementById('Microsoft'); if (el) el.click();
    };

    window.triggerBeazleySignUp = function () {
      // Replace with your exact AAD tenant or B2C sign-up policy URL if needed.
      go('https://login.windows.net/9a50eba8-7568-447a-bcb9-27a0d464aa80/');
    };
  })();
</script>"
}
